// modules/auth/routes/token-refresh.ts
import { Request, Response } from 'bun';
import { defineRoute } from 'aether';
import { requireUser } from '/lib/auth';
import { Result, ok, err } from '/lib/result';
import { parseBody } from '/lib/validate';
import { User, Session, AuthError } from '/modules/auth/types';

export default defineRoute({
  method: 'POST',
  path: '/auth/token-refresh',
  auth: false,
  handler: async (req: Request) => {
    try {
      const body = parseBody<{ refreshToken: string }>(req);
      const { refreshToken } = body;

      // Validate the refresh token
      if (!refreshToken || typeof refreshToken !== 'string') {
        return err(new AuthError('Invalid refresh token'));
      }

      // Retrieve the session associated with the refresh token
      const session = await getSession(refreshToken);

      if (!session) {
        return err(new AuthError('Session not found'));
      }

      // Check if the session is expired
      if (Date.now() > session.expiryTime) {
        return err(new AuthError('Session expired'));
      }

      // Rotate the refresh token
      const newRefreshToken = generateNewRefreshToken();

      // Update the session with the new refresh token
      await updateSession(session.id, newRefreshToken);

      // Generate a new access token
      const accessToken = generateAccessToken(session.userId);

      return ok({
        accessToken,
        refreshToken: newRefreshToken,
      });
    } catch (error) {
      return err(new AuthError('Internal server error'));
    }
  },
});

// Helper functions
function generateNewRefreshToken(): string {
  // Generate a secure refresh token
  return crypto.randomUUID();
}

async function updateSession(sessionId: string, newRefreshToken: string): Promise<void> {
  // Update the session with the new refresh token in the database
  await query('UPDATE sessions SET refresh_token = $1 WHERE id = $2', [newRefreshToken, sessionId]);
}

function generateAccessToken(userId: string): string {
  // Generate a secure access token
  return crypto.randomUUID();
}

